     1→import { useState } from "react";
     2→import { Input } from "@/components/ui/input";
     3→import { Label } from "@/components/ui/label";
     4→import { Switch } from "@/components/ui/switch";
     5→import { CurrencyInput } from "@/components/ui/currency-input";
     6→import { PercentageInput } from "@/components/ui/percentage-input";
     7→import { toast } from "sonner";
     8→
     9→interface ServiceData {
    10→  name: string;
    11→  acceptsOnlineBooking?: boolean;
    12→  price?: number | string;
    13→  duration?: number;
    14→  commission?: number | string;
    15→}
    16→
    17→interface ServiceFormProps {
    18→  initialData?: ServiceData;
    19→  onSave: (data: ServiceData) => void;
    20→  isSaving?: boolean;
    21→  isCustomService?: boolean;
    22→}
    23→
    24→export function ServiceForm({
    25→  initialData,
    26→  onSave,
    27→  isSaving = false,
    28→  isCustomService = false,
    29→}: ServiceFormProps) {
    30→  // Format initial values for masked inputs
    31→  const formatInitialPrice = (price?: number | string): string => {
    32→    if (!price) return "0,00";
    33→    const numValue =
    34→      typeof price === "string" ? parseFloat(price.replace(",", ".")) : price;
    35→    return numValue.toFixed(2).replace(".", ",");
    36→  };
    37→
    38→  const formatInitialCommission = (commission?: number | string): string => {
    39→    if (!commission) return "0,00";
    40→    const numValue =
    41→      typeof commission === "string"
    42→        ? parseFloat(commission.replace(",", "."))
    43→        : commission;
    44→    return numValue.toFixed(2).replace(".", ",");
    45→  };
    46→
    47→  const [serviceData, setServiceData] = useState<ServiceData>({
    48→    name: initialData?.name || "",
    49→    acceptsOnlineBooking: initialData?.acceptsOnlineBooking ?? true,
    50→    price: formatInitialPrice(initialData?.price),
    51→    duration: initialData?.duration || 30,
    52→    commission: formatInitialCommission(initialData?.commission),
    53→  });
    54→
    55→  const [errors, setErrors] = useState<
    56→    Partial<Record<keyof ServiceData, string>>
    57→  >({});
    58→
    59→  const handleInputChange = (
    60→    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
    61→  ) => {
    62→    const { name, value, type } = e.target;
    63→
    64→    setServiceData((prev) => ({
    65→      ...prev,
    66→      [name]: type === "number" ? (value === "" ? 0 : Number(value)) : value,
    67→    }));
    68→
    69→    // Clear error when user starts typing
    70→    if (errors[name as keyof ServiceData]) {
    71→      setErrors((prev) => ({ ...prev, [name]: undefined }));
    72→    }
    73→  };
    74→
    75→  const validateForm = (): boolean => {
    76→    const newErrors: Partial<Record<keyof ServiceData, string>> = {};
    77→
    78→    // Validate name: Required, min 2 characters, max 100 characters
    79→    if (!serviceData.name.trim()) {
    80→      newErrors.name = "Nome é obrigatório";
    81→    } else if (serviceData.name.trim().length < 2) {
    82→      newErrors.name = "Nome deve ter pelo menos 2 caracteres";
    83→    } else if (serviceData.name.length > 100) {
    84→      newErrors.name = "Nome não pode ter mais de 100 caracteres";
    85→    }
    86→
    87→    // Validate price, duration, and commission for custom services
    88→    if (isCustomService) {
    89→      const priceValue =
    90→        typeof serviceData.price === "string"
    91→          ? parseFloat(serviceData.price.replace(".", "").replace(",", "."))
    92→          : serviceData.price;
    93→
    94→      const commissionValue =
    95→        typeof serviceData.commission === "string"
    96→          ? parseFloat(serviceData.commission.replace(",", "."))
    97→          : serviceData.commission;
    98→
    99→      if (priceValue !== undefined && priceValue <= 0) {
   100→        newErrors.price = "Preço deve ser maior que zero";
   101→      }
   102→      if (serviceData.duration !== undefined && serviceData.duration < 1) {
   103→        newErrors.duration = "Duração deve ser pelo menos 1 minuto";
   104→      }
   105→      if (
   106→        commissionValue !== undefined &&
   107→        (commissionValue < 0 || commissionValue > 100)
   108→      ) {
   109→        newErrors.commission = "Comissão deve estar entre 0% e 100%";
   110→      }
   111→    }
   112→
   113→    setErrors(newErrors);
   114→
   115→    if (Object.keys(newErrors).length > 0) {
   116→      const firstError = Object.values(newErrors)[0];
   117→      toast.error(firstError);
   118→      return false;
   119→    }
   120→
   121→    return true;
   122→  };
   123→
   124→  const handleSubmit = (e: React.FormEvent) => {
   125→    e.preventDefault();
   126→
   127→    if (!validateForm()) {
   128→      return;
   129→    }
   130→
   131→    // Convert masked values to numbers before saving
   132→    const dataToSave = {
   133→      ...serviceData,
   134→      price:
   135→        typeof serviceData.price === "string"
   136→          ? parseFloat(serviceData.price.replace(".", "").replace(",", "."))
   137→          : serviceData.price,
   138→      commission:
   139→        typeof serviceData.commission === "string"
   140→          ? parseFloat(serviceData.commission.replace(",", "."))
   141→          : serviceData.commission,
   142→    };
   143→
   144→    onSave(dataToSave);
   145→  };
   146→
   147→  return (
   148→    <form id="service-form" onSubmit={handleSubmit} className="space-y-4">
   149→      <div className="space-y-1">
   150→        <Input
   151→          id="name"
   152→          label="Nome do Serviço"
   153→          name="name"
   154→          type="text"
   155→          value={serviceData.name}
   156→          onChange={handleInputChange}
   157→          placeholder="Digite o nome do serviço"
   158→          required
   159→          disabled={isSaving}
   160→          maxLength={100}
   161→          className={`salon-input${errors.name ? " border-destructive" : ""}`}
   162→        />
   163→        {errors.name && <p className="text-[13px] text-destructive">{errors.name}</p>}
   164→        <p className="text-[13px] text-muted-foreground">
   165→          Mínimo 2 caracteres, máximo 100 caracteres
   166→        </p>
   167→      </div>
   168→
   169→        {/* Show price, duration, and commission fields for custom services */}
   170→        {isCustomService && (
   171→          <>
   172→            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   173→              <div className="space-y-1">
   174→                <Label htmlFor="price" className="text-[13px] font-medium">Preço</Label>
   175→                <CurrencyInput
   176→                  id="price"
   177→                  value={serviceData.price as string}
   178→                  onChange={(value) =>
   179→                    setServiceData((prev) => ({ ...prev, price: value }))
   180→                  }
   181→                  disabled={isSaving}
   182→                  className={errors.price ? "border-destructive" : ""}
   183→                  placeholder="Ex: R$ 50,00"
   184→                />
   185→                {errors.price && (
   186→                  <p className="text-[13px] text-destructive">{errors.price}</p>
   187→                )}
   188→              </div>
   189→
   190→              <div className="space-y-1">
   191→                <Label htmlFor="duration" className="text-[13px] font-medium">Duração (minutos)</Label>
   192→                <Input
   193→                  id="duration"
   194→                  name="duration"
   195→                  type="number"
   196→                  min="15"
   197→                  step={15}
   198→                  value={serviceData.duration || ""}
   199→                  onChange={handleInputChange}
   200→                  placeholder="30"
   201→                  disabled={isSaving}
   202→                  className={`salon-input${errors.duration ? " border-destructive" : ""}`}
   203→                />
   204→                {errors.duration && (
   205→                  <p className="text-[13px] text-destructive">{errors.duration}</p>
   206→                )}
   207→              </div>
   208→            </div>
   209→
   210→            <div className="space-y-1">
   211→              <Label htmlFor="commission" className="text-[13px] font-medium">Comissão (%)</Label>
   212→              <PercentageInput
   213→                id="commission"
   214→                value={serviceData.commission as string}
   215→                onChange={(value) =>
   216→                  setServiceData((prev) => ({ ...prev, commission: value }))
   217→                }
   218→                disabled={isSaving}
   219→                className={errors.commission ? "border-destructive" : ""}
   220→              />
   221→              {errors.commission && (
   222→                <p className="text-[13px] text-destructive">{errors.commission}</p>
   223→              )}
   224→            </div>
   225→          </>
   226→        )}
   227→
   228→      <div className="flex items-center justify-between bg-card border border-border rounded-lg p-4">
   229→        <div className="space-y-0.5">
   230→          <Label htmlFor="acceptsOnlineBooking" className="text-[13px] font-semibold">
   231→            Agendamento Online
   232→          </Label>
   233→          <p className="text-[13px] text-muted-foreground">
   234→            Disponibilizar para clientes agendarem via web
   235→          </p>
   236→        </div>
   237→        <Switch
   238→          id="acceptsOnlineBooking"
   239→          checked={serviceData.acceptsOnlineBooking}
   240→          onCheckedChange={(checked) =>
   241→            setServiceData((prev) => ({
   242→              ...prev,
   243→              acceptsOnlineBooking: checked,
   244→            }))
   245→          }
   246→          disabled={isSaving}
   247→        />
   248→      </div>
   249→    </form>
   250→  );
   251→}
   252→

